import React from 'react'
import { Link } from '@fs/zion-router'
import { useTranslation } from 'react-i18next'
import { SendMessageButton } from '../SendMessageButton'
import { trackEvent } from '../ContactHooks'
import isFamilySearch from '../isFamilySearch'

function SendMessageAction({ isSelf, helpee, contact, disabled, sendMessageButtonProps }) {
  const { userLoading: helpeeLoading, contactName: isHelpee } = helpee
  const allowMessaging = !isFamilySearch(contact?.cisId)

  if (isSelf === false && !helpeeLoading) {
    return (
      <SendMessageButton
        emphasis="high"
        contact={contact}
        {...sendMessageButtonProps}
        disabled={disabled || isHelpee || !allowMessaging}
        linkName="PersonContactCard:sendMessage:clicked"
        showIcon
      />
    )
  }
  return null
}

export default function ContactActionButton({ isSelf, helpee, contact, disabled, sendMessageButtonProps }) {
  const { t } = useTranslation()
  const sendMessageActionProps = {
    isSelf,
    helpee,
    contact,
    disabled,
    sendMessageButtonProps,
  }

  if (isSelf) {
    return (
      <Link to="/profile/contact" onClick={trackEvent('editContactSettings:clicked')} external target="_blank">
        {t('go-to.settings', 'Go to Settings')}
      </Link>
    )
  }
  return <SendMessageAction {...sendMessageActionProps} />
}
