import React from 'react'
import PropTypes from 'prop-types'
import { CHANNEL_TYPE, useChatOverlay } from '@fs/zion-chat'
import { SocialChat } from '@fs/zion-icon'
import { Button } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { track } from '../ContactHooks/useContactAnalytics'

const hasWindow = typeof window !== 'undefined'
const hasDocument = typeof document !== 'undefined'

function SendMessageButton({
  contact,
  aboutText = hasDocument ? document.title : '',
  aboutUrl = hasWindow ? window.location.href : '',
  disableAbout = false,
  disabled,
  linkName,
  showIcon,
  emphasis,
}) {
  const { t } = useTranslation()
  const chatRoute = `/chat-create/${CHANNEL_TYPE.FS_DIRECT}`
  const about = disableAbout ? undefined : { text: aboutText, link: aboutUrl }
  const supportChatInformation = { to: [contact?.cisId], about }
  const buttonRef = React.useRef()
  const { handleClick } = useChatOverlay(chatRoute, supportChatInformation, false, buttonRef)

  return (
    <Button
      emphasis={emphasis}
      onClick={(event) => {
        track(linkName || 'chatButton:clicked', event?.target)
        handleClick(event)
      }}
      Icon={showIcon && SocialChat}
      disabled={disabled}
      data-testid="chat-create-button"
      fullWidth
      ref={buttonRef}
    >
      {t('chat.open-direct.action', 'Chat')}
    </Button>
  )
}

SendMessageButton.propTypes = {
  /** User message is being sent to */
  contact: PropTypes.shape({
    cisId: PropTypes.string,
  }).isRequired,
  /** Sets the about text in the Chat message */
  aboutText: PropTypes.string,
  /** Sent the About Url in the Chat message */
  aboutUrl: PropTypes.string,
  /** If true, removes the about text from the Chat message */
  disableAbout: PropTypes.bool,
  /** Shows send message icon */
  showIcon: PropTypes.bool,
}

export default SendMessageButton
